proof fn lemma_receive_ack_post_send_state(
    pre: SingleDelivery<Message>,
    pkt: Packet,
    post1: SingleDelivery<Message>,
    post2: SingleDelivery<Message>,
)
    requires
        pkt.msg is Ack,
        SingleDelivery::receive_ack(pre, post1, pkt, set!{}),
        SingleDelivery::receive_ack(pre, post2, pkt, set!{}),
    ensures
        post1.send_state == post2.send_state,
        ({
            let old_ack_state = ack_state_lookup(pkt.src, pre.send_state);
            let ack_seqno = pkt.msg.arrow_Ack_ack_seqno();
            !(ack_seqno > old_ack_state.num_packets_acked) ==> (post1 == pre && post2 == pre)
        }),
{
    let old_ack_state = ack_state_lookup(pkt.src, pre.send_state);
    let ack_seqno = pkt.msg.arrow_Ack_ack_seqno();
    if ack_seqno > old_ack_state.num_packets_acked {
        let new_ack_state = AckState::<Message> {
            num_packets_acked: ack_seqno,
            un_acked: truncate_un_ack_list(old_ack_state.un_acked, ack_seqno),
            ..old_ack_state
        };
        let new_send_state = pre.send_state.insert(pkt.src, new_ack_state);
        assert(post1 =~= SingleDelivery::<Message> { send_state: new_send_state, ..post1 });
        assert(post2 =~= SingleDelivery::<Message> { send_state: new_send_state, ..post2 });
        assert(post1.send_state =~= new_send_state);
        assert(post2.send_state =~= new_send_state);
        assert(post1.send_state == post2.send_state);
    } else {
        assert(post1 == pre);
        assert(post2 == pre);
        assert(post1.send_state == post2.send_state);
    }
}
